import { createPortal } from 'react-dom';
import { useEffect } from 'react';

export function Modal({ open, onClose, children }: { open: boolean; onClose: () => void; children: React.ReactNode }) {
  useEffect(() => {
    const onKey = (e: KeyboardEvent) => { if (e.key === 'Escape') onClose(); };
    document.addEventListener('keydown', onKey);
    return () => document.removeEventListener('keydown', onKey);
  }, [onClose]);
  if (!open) return null;
  return createPortal(
    <div className="overlay" onClick={onClose}>
      <div className="dialog" onClick={e => e.stopPropagation()}>{children}</div>
    </div>,
    document.body
  );
}

type Entry = { restore: HTMLElement | null };
const stack: Entry[] = [];
export function pushModal(): Entry {
  const entry: Entry = { restore: (document.activeElement as HTMLElement) ?? null };
  stack.push(entry);
  return entry;
}
export function popModal(entry: Entry) {
  const idx = stack.lastIndexOf(entry);
  if (idx >= 0) stack.splice(idx, 1);
  entry.restore?.focus?.();
}
export function isTopmost(entry: Entry) { return stack[stack.length - 1] === entry; }

const SEL = ['a[href]','button:not([disabled])','input:not([disabled])','select:not([disabled])','textarea:not([disabled])','[tabindex]:not([tabindex="-1"])'].join(',');
export function tabbables(root: HTMLElement): HTMLElement[] {
  return Array.from(root.querySelectorAll<HTMLElement>(SEL)).filter(el => el.offsetParent !== null || el === document.activeElement);
}

import { createPortal } from 'react-dom';
import { useEffect, useRef } from 'react';
import { pushModal, popModal, isTopmost } from '../a11y/focusStack';
import { tabbables } from '../a11y/tabbable';

export function Modal({ open, onClose, label, children }: { open: boolean; onClose: () => void; label: string; children: React.ReactNode }) {
  const dialogRef = useRef<HTMLDivElement>(null);
  useEffect(() => {
    if (!open) return;
    const entry = pushModal();
    const root = dialogRef.current!;
    const siblings = Array.from(document.body.children).filter(c => !root.contains(c)) as HTMLElement[];
    siblings.forEach(s => s.setAttribute('inert', ''));
    (tabbables(root)[0] ?? root).focus();
    const onKey = (e: KeyboardEvent) => {
      if (!isTopmost(entry)) return;
      if (e.key === 'Escape') return onClose();
      if (e.key !== 'Tab') return;
      const items = tabbables(root);
      if (items.length === 0) { e.preventDefault(); return; }
      const first = items[0], last = items[items.length - 1];
      if (e.shiftKey && document.activeElement === first) { e.preventDefault(); last.focus(); }
      else if (!e.shiftKey && document.activeElement === last) { e.preventDefault(); first.focus(); }
    };
    document.addEventListener('keydown', onKey, true);
    return () => {
      document.removeEventListener('keydown', onKey, true);
      siblings.forEach(s => s.removeAttribute('inert'));
      popModal(entry);
    };
  }, [open, onClose]);
  if (!open) return null;
  return createPortal(
    <div className="overlay" onClick={onClose}>
      <div ref={dialogRef} role="dialog" aria-modal="true" aria-label={label} tabIndex={-1} className="dialog" onClick={e => e.stopPropagation()}>{children}</div>
    </div>,
    document.body
  );
}

