import { Component, Input } from '@angular/core';
type Col = { key: string; label: string };
@Component({ selector: 'grid-header', templateUrl: './header.component.html' })
export class HeaderComponent {
  @Input() columns: Col[] = [];
  sortKey = '';
  sortDir: 'asc' | 'desc' = 'asc';
  ariaSort(c: Col): 'none' | 'ascending' | 'descending' {
    if (this.sortKey !== c.key) return 'none';
    return this.sortDir === 'asc' ? 'ascending' : 'descending';
  }
  sortLabel(c: Col) {
    const next = this.sortKey === c.key && this.sortDir === 'asc' ? 'descending' : 'ascending';
    return `Sort by ${c.label}, ${next}`;
  }
  sort(c: Col) {
    if (this.sortKey === c.key) this.sortDir = this.sortDir === 'asc' ? 'desc' : 'asc';
    else { this.sortKey = c.key; this.sortDir = 'asc'; }
  }
}

export function makeComparator<T>(key: keyof T, dir: 'asc' | 'desc') {
  const sign = dir === 'asc' ? 1 : -1;
  return (a: T, b: T) => {
    const av = a[key], bv = b[key];
    if (av === bv) return 0;
    return (av < bv ? -1 : 1) * sign;
  };
}

