import { create } from 'zustand';
type S = { polite: string; assertive: string; _seen: Map<string, number>; announce: (msg: string, assertive: boolean) => void };
export const useAnnouncer = create<S>((set, get) => ({
  polite: '', assertive: '', _seen: new Map(),
  announce: (msg, assertive) => {
    const now = Date.now();
    const last = get()._seen.get(msg) ?? 0;
    if (now - last < 500) return; // dedupe rapid repeats
    get()._seen.set(msg, now);
    // force re-announce by clearing then setting on next tick
    const key = assertive ? 'assertive' : 'polite';
    set({ [key]: '' } as any);
    setTimeout(() => set({ [key]: msg } as any), 50);
  },
}));

import { useEffect, useRef } from 'react';
import { useToasts } from './store';
import { useAnnouncer } from './announcer';
export function ToastHost() {
  const toasts = useToasts();
  const announce = useAnnouncer(s => s.announce);
  const seen = useRef(new Set<string>());
  useEffect(() => {
    for (const t of toasts) {
      if (seen.current.has(t.id)) continue;
      seen.current.add(t.id);
      announce(t.message, t.kind === 'error');
    }
  }, [toasts, announce]);
  return (
    <div className="toast-host" aria-hidden="true">
      {toasts.map(t => <div key={t.id} className={`toast toast-${t.kind}`}>{t.message}</div>)}
    </div>
  );
}

