import json, functools
from fastapi import Request
from fastapi.exceptions import RequestValidationError
from fastapi.responses import JSONResponse
from pyicu_messageformat import MessageFormat  # thin ICU wrapper
from .i18n import pick_locale, KEYS

@functools.lru_cache(maxsize=8)
def _catalog(locale: str) -> dict:
    try:
        return json.load(open(f'app/messages/{locale}.json'))
    except FileNotFoundError:
        return json.load(open('app/messages/en.json'))

async def validation_handler(request: Request, exc: RequestValidationError):
    locale = pick_locale(request.headers.get('accept-language'))
    cat = _catalog(locale)
    out = []
    for e in exc.errors():
        code, key = KEYS.get(e['type'], ('invalid', 'errors.invalid'))
        field = str(e['loc'][-1])
        ctx = {'field': field, 'limit': e.get('ctx', {}).get('min_length', 0)}
        msg = MessageFormat(cat.get(key, key), locale).format(ctx)
        out.append({'code': code, 'field': field, 'message': msg})
    return JSONResponse(status_code=422, content={'errors': out})

