import json, functools, threading
from icu_messageformat import compile as icu_compile  # compiles to a callable

_lock = threading.Lock()

@functools.lru_cache(maxsize=64)
def _compiled(locale: str, key: str):
    with _lock:
        try:
            cat = json.load(open(f'notify/catalogs/{locale}.json'))
        except FileNotFoundError:
            cat = json.load(open('notify/catalogs/en.json'))
    return icu_compile(cat.get(key) or json.load(open('notify/catalogs/en.json'))[key], locale)

def render(key: str, locale: str, **args) -> str:
    return _compiled(locale, key)(args)

def render_like(actor_name, n, locale):
    return render('like', locale, actor=actor_name, count=n)

def render_follow(actor_name, actor_gender, locale):
    return render('follow', locale, actor=actor_name, gender=actor_gender)

