import { useState, useCallback } from 'react';
export function useCombobox(count: number, onPick: (i: number) => void) {
  const [active, setActive] = useState(-1);
  const [open, setOpen] = useState(false);
  const onKeyDown = useCallback((e: React.KeyboardEvent) => {
    if (!open && (e.key === 'ArrowDown' || e.key === 'ArrowUp')) { setOpen(true); return; }
    switch (e.key) {
      case 'ArrowDown': e.preventDefault(); setActive(a => Math.min(a + 1, count - 1)); break;
      case 'ArrowUp': e.preventDefault(); setActive(a => Math.max(a - 1, 0)); break;
      case 'Home': e.preventDefault(); setActive(0); break;
      case 'End': e.preventDefault(); setActive(count - 1); break;
      case 'Enter': if (active >= 0) { e.preventDefault(); onPick(active); } break;
      case 'Escape': setOpen(false); setActive(-1); break;
    }
  }, [open, count, active, onPick]);
  return { active, open, setOpen, setActive, onKeyDown };
}

import { useId, useRef, useState, useEffect } from 'react';
import { useCombobox } from './useCombobox';
export function Autocomplete({ fetchItems, onSelect, label }: { fetchItems: (q: string) => Promise<Item[]>; onSelect: (i: Item) => void; label: string }) {
  const listId = useId();
  const [items, setItems] = useState<Item[]>([]);
  const [announce, setAnnounce] = useState('');
  const { active, open, setOpen, setActive, onKeyDown } = useCombobox(items.length, i => { onSelect(items[i]); setOpen(false); });
  useEffect(() => { setAnnounce(open ? `${items.length} results` : ''); }, [items.length, open]);
  const activeId = active >= 0 ? `${listId}-opt-${active}` : undefined;
  return (
    <div className="ac">
      <input role="combobox" aria-expanded={open} aria-controls={listId} aria-activedescendant={activeId} aria-autocomplete="list" aria-label={label}
        onKeyDown={onKeyDown}
        onChange={async e => { const r = await fetchItems(e.target.value); setItems(r); setOpen(true); setActive(-1); }} />
      <ul role="listbox" id={listId} hidden={!open} className="results">
        {items.map((i, idx) => (
          <li key={i.id} id={`${listId}-opt-${idx}`} role="option" aria-selected={idx === active} onMouseDown={e => { e.preventDefault(); onSelect(i); setOpen(false); }}>{i.label}</li>
        ))}
      </ul>
      <div aria-live="polite" className="sr-only">{announce}</div>
    </div>
  );
}

// Renders a windowed slice but keeps the active option mounted so aria-activedescendant resolves
export function visibleRange(active: number, total: number, win = 50) {
  const start = Math.max(0, Math.min(active - win / 2, total - win));
  return { start: Math.max(0, start), end: Math.min(total, start + win) };
}

