package telemetry

import (
	"golang.org/x/text/language"
	"golang.org/x/text/message"
)

type Units string

const (
	Metric   Units = "metric"
	Imperial Units = "imperial"
)

func FormatTemp(celsius float64, tag language.Tag, u Units) (string, float64) {
	p := message.NewPrinter(tag)
	if u == Imperial {
		f := celsius*9/5 + 32
		return p.Sprintf("%.2f\u00b0F", f), f
	}
	return p.Sprintf("%.2f\u00b0C", celsius), celsius
}

func FormatValue(v float64, tag language.Tag) string {
	return message.NewPrinter(tag).Sprintf("%.2f", v)
}

package telemetry

import (
	"net/http"
	"golang.org/x/text/language"
)

var matcher = language.NewMatcher([]language.Tag{language.English, language.German, language.French, language.Japanese})

func Negotiate(r *http.Request) (language.Tag, Units) {
	tag, _ := language.MatchStrings(matcher, r.Header.Get("Accept-Language"))
	units := Units(r.Header.Get("X-Unit-System"))
	if units != Metric && units != Imperial {
		units = Metric
	}
	return tag, units
}

