import { i18n, SUPPORTED } from './index';
const modules = import.meta.glob('./locales/*.json'); // each becomes a lazy chunk
const loaded = new Set<string>(['en']);
export async function loadLocale(locale: string): Promise<string> {
  const code = SUPPORTED.includes(locale) ? locale : 'en';
  if (!loaded.has(code)) {
    const importer = modules[`./locales/${code}.json`];
    if (importer) {
      const mod: any = await importer();
      i18n.global.setLocaleMessage(code, mod.default);
      loaded.add(code);
    }
  }
  i18n.global.locale.value = code as any;
  document.documentElement.lang = code;
  return code;
}

