import IntlMessageFormat from 'intl-messageformat';
import { catalogFor } from './catalogs';
export function renderEmail(ev: any, profile: { locale: string; tz: string }, version: string) {
  const locale = profile.locale || 'en';
  const tz = profile.tz || 'UTC';
  const cat = catalogFor(version, locale);
  const eta = new Intl.DateTimeFormat(locale, { dateStyle: 'full', timeStyle: 'short', timeZone: tz }).format(new Date(ev.etaIso));
  const subject = new IntlMessageFormat(cat['email.subject'], locale).format({ trackingId: ev.trackingId }) as string;
  const body = new IntlMessageFormat(cat['email.body'], locale).format({ trackingId: ev.trackingId, eta }) as string;
  return { subject, body };
}

