    setErrors(errs);
    const firstBad = order.find(f => errs[f]);
    if (firstBad) {
      setSummary(`${Object.keys(errs).length} errors. Please review the form.`);
      refs.current[firstBad]?.focus();
    } else setSummary('');
  }
  return (
    <form onSubmit={handle} noValidate>
      <div aria-live="assertive" role="alert" className="sr-only">{summary}</div>
      <Field name="email" label="Email" error={errors.email} inputRef={el => (refs.current.email = el)} />
      <Field name="password" label="Password" type="password" error={errors.password} inputRef={el => (refs.current.password = el)} />
      <button>Sign up</button>
    </form>
  );
}

