import { useState, useCallback } from 'react';
type Pos = { col: number; idx: number };
export function useKeyboardDnd(move: (from: Pos, to: Pos) => Promise<void>, announce: (m: string) => void, layout: () => { cols: number; sizes: number[] }) {
  const [grabbed, setGrabbed] = useState<Pos | null>(null);
  const onKeyDown = useCallback(async (e: React.KeyboardEvent, pos: Pos, title: string) => {
    const { cols, sizes } = layout();
    if (e.key === ' ' || e.key === 'Enter') {
      e.preventDefault();
      if (!grabbed) { setGrabbed(pos); announce(`Grabbed ${title}, position ${pos.idx + 1}`); }
      else { const to = grabbed; setGrabbed(null); try { await move(grabbed, pos); announce(`Dropped ${title} in column ${pos.col + 1}, position ${pos.idx + 1}`); } catch { announce('Move failed, card returned'); } }
    } else if (grabbed && e.key === 'Escape') { setGrabbed(null); announce('Move cancelled'); }
    else if (grabbed) {
      let { col, idx } = grabbed;
      if (e.key === 'ArrowDown') idx = Math.min(idx + 1, sizes[col] - 1);
      if (e.key === 'ArrowUp') idx = Math.max(idx - 1, 0);
      if (e.key === 'ArrowRight') col = Math.min(col + 1, cols - 1);
      if (e.key === 'ArrowLeft') col = Math.max(col - 1, 0);
      if (col !== grabbed.col || idx !== grabbed.idx) { e.preventDefault(); setGrabbed({ col, idx }); announce(`Column ${col + 1}, position ${idx + 1}`); }
    }
  }, [grabbed, move, announce, layout]);
  return { grabbed, onKeyDown };
}

import { useDrag } from 'react-dnd';
export function Card({ card, pos, grabbed, onKeyDown }: any) {
  const [, drag] = useDrag(() => ({ type: 'card', item: { id: card.id } }));
  const isGrabbed = grabbed && grabbed.col === pos.col && grabbed.idx === pos.idx;
  return (
    <div ref={drag} className="card" tabIndex={0} role="button" aria-roledescription="draggable card"
      aria-grabbed={isGrabbed || undefined}
      onKeyDown={e => onKeyDown(e, pos, card.title)}>{card.title}</div>
  );
}

import { useAnnouncer } from './announcer';
import { useKeyboardDnd } from './useKeyboardDnd';
export function Board({ columns, moveCard }: any) {
  const announce = useAnnouncer(s => s.announce);
  const { grabbed, onKeyDown } = useKeyboardDnd(
    async (from, to) => { await moveCard(from, to); },
    m => announce(m, true),
    () => ({ cols: columns.length, sizes: columns.map((c: any) => c.cards.length) })
  );
  return (
    <div className="board">{columns.map((c: any, ci: number) => (
      <div key={c.id} className="col" role="list" aria-label={c.name}>{c.cards.map((card: any, idx: number) => (
        <Card key={card.id} card={card} pos={{ col: ci, idx }} grabbed={grabbed} onKeyDown={onKeyDown} />
      ))}</div>
    ))}</div>
  );
}

