export function separators(locale: string) {
  const parts = new Intl.NumberFormat(locale).formatToParts(11111.1);
  const group = parts.find(p => p.type === 'group')?.value ?? ',';
  const decimal = parts.find(p => p.type === 'decimal')?.value ?? '.';
  return { group, decimal };
}
export function parseToMinor(input: string, locale: string, fractionDigits = 2): number | null {
  const { group, decimal } = separators(locale);
  const cleaned = input.split(group).join('').replace(decimal, '.');
  if (!/^[-]?\d*(?:\.\d*)?$/.test(cleaned) || cleaned === '' || cleaned === '.') return null;
  const [int, frac = ''] = cleaned.split('.');
  const fracPadded = (frac + '0'.repeat(fractionDigits)).slice(0, fractionDigits);
  return parseInt(int + fracPadded, 10);
}
export function formatMinor(minor: number, locale: string, currency: string) {
  return new Intl.NumberFormat(locale, { style: 'currency', currency }).format(minor / 100);
}

import { useState } from 'react';
import { separators, parseToMinor, formatMinor } from './localeNumber';
export function AmountInput({ locale, currency, onChange, label }: { locale: string; currency: string; onChange: (minor: number | null) => void; label: string }) {
  const [text, setText] = useState('');
  const { group, decimal } = separators(locale);
  function handle(e: React.ChangeEvent<HTMLInputElement>) {
    const raw = e.target.value.replace(new RegExp(`[^0-9${escapeReg(group)}${escapeReg(decimal)}-]`, 'g'), '');
    setText(raw);
    onChange(parseToMinor(raw, locale));
  }
  function blurFormat() {
    const minor = parseToMinor(text, locale);
    if (minor != null) setText(formatMinor(minor, locale, currency).replace(/[^0-9.,\u00a0 ]/g, '').trim());
  }
  return <input inputMode="decimal" aria-label={label} value={text} onChange={handle} onBlur={blurFormat} />;
}
function escapeReg(s: string) { return s.replace(/[.*+?^${}()|[\]\\]/g, '\\$&'); }

