import { Project, SyntaxKind } from 'ts-morph';
import fs from 'node:fs';
import allowlist from '../i18n/dynamic-keys.json';

export function extractKeys(globs: string[]): Set<string> {
  const project = new Project({ tsConfigFilePath: 'tsconfig.json' });
  project.addSourceFilesAtPaths(globs);
  const keys = new Set<string>();
  for (const sf of project.getSourceFiles()) {
    sf.forEachDescendant(node => {
      if (node.getKind() !== SyntaxKind.CallExpression) return;
      const call = node.asKind(SyntaxKind.CallExpression)!;
      const name = call.getExpression().getText();
      if (name !== 't' && !name.endsWith('.t')) return;
      const arg = call.getArguments()[0];
      if (arg && arg.getKind() === SyntaxKind.StringLiteral) keys.add(arg.getText().slice(1, -1));
    });
  }
  return keys;
}

if (require.main === module) {
  const used = extractKeys(['src/**/*.{ts,tsx}']);
  const en: Record<string, string> = JSON.parse(fs.readFileSync('i18n/en.json', 'utf8'));
  const allow = new Set<string>(allowlist as string[]);
  const missing = [...used].filter(k => !(k in en) && !allow.has(k));
  const orphan = Object.keys(en).filter(k => !used.has(k) && !allow.has(k));
  if (orphan.length) console.warn('Orphaned keys:', orphan.length, orphan.slice(0, 10));
  if (missing.length) {
    console.error('Missing translations:', missing);
    process.exit(1);
  }
  console.log('i18n keys OK:', used.size);
}

