import { useRef, useState, useEffect } from 'react';
import { CaptionMenu } from './CaptionMenu';
export function Player({ src, tracks }: { src: string; tracks: { lang: string; label: string; url: string }[] }) {
  const v = useRef<HTMLVideoElement>(null);
  const [playing, setPlaying] = useState(false);
  const [t, setT] = useState(0);
  const [dur, setDur] = useState(0);
  const [announce, setAnnounce] = useState('');
  const lastAnn = useRef(0);
  useEffect(() => {
    const el = v.current!;
    const onTime = () => { setT(el.currentTime); if (Math.floor(el.currentTime) - lastAnn.current >= 30) { lastAnn.current = Math.floor(el.currentTime); setAnnounce(fmt(el.currentTime)); } };
    const onMeta = () => setDur(el.duration);
    el.addEventListener('timeupdate', onTime); el.addEventListener('loadedmetadata', onMeta);
    return () => { el.removeEventListener('timeupdate', onTime); el.removeEventListener('loadedmetadata', onMeta); };
  }, []);
  function toggle() { const el = v.current!; if (el.paused) { el.play(); setPlaying(true); } else { el.pause(); setPlaying(false); } }
  return (
    <div className="player">
      <video ref={v} src={src} crossOrigin="anonymous">
        {tracks.map(tr => <track key={tr.lang} kind="subtitles" srcLang={tr.lang} label={tr.label} src={tr.url} />)}
      </video>
      <div className="controls">
        <button type="button" onClick={toggle} aria-pressed={playing} aria-label={playing ? 'Pause' : 'Play'}>{playing ? '\u23f8' : '\u25b6'}</button>
        <input type="range" className="seek" min={0} max={dur || 0} value={t} step={0.1}
          aria-label="Seek" aria-valuetext={`${fmt(t)} of ${fmt(dur)}`}
          onChange={e => { const nt = Number(e.target.value); v.current!.currentTime = nt; setT(nt); }} />
        <CaptionMenu video={v} tracks={tracks} />
      </div>
      <div aria-live="polite" className="sr-only">{announce}</div>
    </div>
  );
}
function fmt(s: number) { const m = Math.floor(s / 60); const sec = Math.floor(s % 60); return `${m}:${String(sec).padStart(2, '0')}`; }

import { useState } from 'react';
export function CaptionMenu({ video, tracks }: { video: React.RefObject<HTMLVideoElement>; tracks: { lang: string; label: string }[] }) {
