  const lines = rows.map(r => `${r.date},${(r.amountCents / 100).toFixed(2)},${r.desc}`);
  return [header, ...lines].join('\n');
}

export function localeCsvMeta(locale: string) {
  const decimal = new Intl.NumberFormat(locale).formatToParts(1.1).find(p => p.type === 'decimal')!.value;
  const delimiter = decimal === ',' ? ';' : ',';
  return { decimal, delimiter };
}
export function num(amountCents: number, locale: string) {
  return new Intl.NumberFormat(locale, { minimumFractionDigits: 2, maximumFractionDigits: 2, useGrouping: false }).format(amountCents / 100);
}
export function day(iso: string, locale: string) {
  return new Intl.DateTimeFormat(locale, { dateStyle: 'short', timeZone: 'UTC' }).format(new Date(iso));
}
export function escape(field: string, delimiter: string) {
  return /["\n\r]/.test(field) || field.includes(delimiter) ? '"' + field.replace(/"/g, '""') + '"' : field;
}

import { Readable } from 'node:stream';
import { localeCsvMeta, num, day, escape } from './exportFormat';
const HEADERS: Record<string, [string, string, string]> = {
  en: ['Date', 'Amount', 'Description'],
  de: ['Datum', 'Betrag', 'Beschreibung'],
};
export function csvStream(rowSource: AsyncIterable<Tx>, locale: string): Readable {
  const lang = locale.split('-')[0];
  const { delimiter } = localeCsvMeta(locale);
  const head = (HEADERS[lang] ?? HEADERS.en).join(delimiter);
  async function* gen() {
    yield '\uFEFF' + head + '\r\n'; // BOM so Excel detects UTF-8
    for await (const r of rowSource) {
      const cols = [day(r.date, locale), num(r.amountCents, locale), escape(r.desc, delimiter)];
      yield cols.join(delimiter) + '\r\n';
    }
  }
  return Readable.from(gen());
}

