import { useState } from 'react';
export function ResultsTable({ rows, cols, caption }: { rows: Row[]; cols: Col[]; caption: string }) {
  const [sort, setSort] = useState<{ key: string; dir: 'asc' | 'desc' } | null>(null);
  function ariaSort(k: string): 'none' | 'ascending' | 'descending' { return sort?.key === k ? (sort.dir === 'asc' ? 'ascending' : 'descending') : 'none'; }
  function onSort(k: string) { setSort(s => s?.key === k ? { key: k, dir: s.dir === 'asc' ? 'desc' : 'asc' } : { key: k, dir: 'asc' }); }
  return (
    <table className="results">
      <caption>{caption}</caption>
      <thead>
