          {cols.map(c => (
            <th key={c.key} scope="col" aria-sort={c.sortable ? ariaSort(c.key) : undefined}>
              {c.sortable ? <button type="button" onClick={() => onSort(c.key)}>{c.label}</button> : c.label}
            </th>
          ))}
        </tr>
      </thead>
      <tbody>
        {rows.map(r => (
          <tr key={r.id}>
            <th scope="row">{r.label}</th>
            {cols.slice(1).map(c => (
              <td key={c.key}>{c.unit ? `${r[c.key]} ${c.unit}` : r[c.key]}</td>
            ))}
