var collations = map[string]string{"sv": "sv_icu", "de": "de_icu", "en": "en_icu"}

func List(db *sql.DB, locale string, limit int) ([]string, error) {
	coll, ok := collations[locale]
	if !ok { coll = "en_icu" } // safe default; not user-controlled string interpolation beyond whitelist
	q := fmt.Sprintf(`SELECT name FROM contacts ORDER BY name COLLATE %s, id LIMIT $1`, coll)
	rows, err := db.Query(q, limit)
	if err != nil { return nil, err }
	defer rows.Close()
