      ))}
    </div>
  );
}

export function move(active: Date, key: string): Date | null {
  const d = new Date(active);
  switch (key) {
    case 'ArrowRight': d.setDate(d.getDate() + 1); break;
    case 'ArrowLeft': d.setDate(d.getDate() - 1); break;
    case 'ArrowDown': d.setDate(d.getDate() + 7); break;
    case 'ArrowUp': d.setDate(d.getDate() - 7); break;
    case 'PageUp': d.setMonth(d.getMonth() - 1); break;
    case 'PageDown': d.setMonth(d.getMonth() + 1); break;
    case 'Home': d.setDate(d.getDate() - d.getDay()); break;
    case 'End': d.setDate(d.getDate() + (6 - d.getDay())); break;
    default: return null;
  }
  return d;
}

import { useState, useEffect, useRef } from 'react';
import { move } from './useDateGrid';
export function Calendar({ month, locale, isDisabled, selected, onPick }: { month: Date; locale: string; isDisabled: (d: Date) => boolean; selected?: Date; onPick: (d: Date) => void }) {
  const [active, setActive] = useState(selected ?? new Date(month.getFullYear(), month.getMonth(), 1));
  const [announce, setAnnounce] = useState('');
  const fmt = new Intl.DateTimeFormat(locale, { weekday: 'long', day: 'numeric', month: 'long', year: 'numeric' });
  const wd = new Intl.DateTimeFormat(locale, { weekday: 'short' });
  const ref = useRef<HTMLButtonElement>(null);
  useEffect(() => { ref.current?.focus(); }, [active]);
  const days = monthDays(month, locale);
  function onKey(e: React.KeyboardEvent) {
    const next = move(active, e.key);
    if (next) { e.preventDefault(); setActive(next); setAnnounce(fmt.format(next)); }
    else if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); if (!isDisabled(active)) { onPick(active); setAnnounce(`Selected ${fmt.format(active)}`); } }
  }
  return (
    <div role="grid" aria-label={new Intl.DateTimeFormat(locale, { month: 'long', year: 'numeric' }).format(month)} onKeyDown={onKey}>
      <div role="row">{weekdayOrder(locale).map(i => <span key={i} role="columnheader">{wd.format(new Date(2026, 5, 1 + i))}</span>)}</div>
      {chunk(days, 7).map((week, wi) => (
        <div role="row" key={wi}>{week.map(d => {
          const isActive = sameDay(d, active);
          return (
            <button key={+d} ref={isActive ? ref : undefined} role="gridcell" type="button"
              tabIndex={isActive ? 0 : -1}
              aria-selected={selected && sameDay(d, selected) ? true : undefined}
              aria-disabled={isDisabled(d) || undefined}
              aria-current={isToday(d) ? 'date' : undefined}
              onClick={() => !isDisabled(d) && onPick(d)}>{d.getDate()}</button>
          );
        })}</div>
      ))}
      <div aria-live="polite" className="sr-only">{announce}</div>
    </div>
  );
}

