import { useState, useCallback } from 'react';
export function useTablist(ids: string[], orientation: 'horizontal' | 'vertical', manual: boolean, onChange?: (id: string) => void) {
  const [selected, setSelected] = useState(ids[0]);
  const [focused, setFocused] = useState(ids[0]);
  const nextKey = orientation === 'horizontal' ? 'ArrowRight' : 'ArrowDown';
  const prevKey = orientation === 'horizontal' ? 'ArrowLeft' : 'ArrowUp';
  const onKeyDown = useCallback((e: React.KeyboardEvent, id: string) => {
    const i = ids.indexOf(id);
    let next = -1;
    if (e.key === nextKey) next = (i + 1) % ids.length;
    else if (e.key === prevKey) next = (i - 1 + ids.length) % ids.length;
    else if (e.key === 'Home') next = 0;
    else if (e.key === 'End') next = ids.length - 1;
    else if ((e.key === 'Enter' || e.key === ' ') && manual) { setSelected(id); onChange?.(id); return; }
    if (next >= 0) { e.preventDefault(); const nid = ids[next]; setFocused(nid); if (!manual) { setSelected(nid); onChange?.(nid); } }
  }, [ids, nextKey, prevKey, manual, onChange]);
  return { selected, focused, setSelected, setFocused, onKeyDown };
}

import { useTablist } from './useTablist';
export function Tabs({ tabs, orientation = 'horizontal', manual = false, label, onChange }: { tabs: { id: string; label: string; content: React.ReactNode }[]; orientation?: 'horizontal' | 'vertical'; manual?: boolean; label: string; onChange?: (id: string) => void }) {
  const ids = tabs.map(t => t.id);
  const { selected, focused, setSelected, setFocused, onKeyDown } = useTablist(ids, orientation, manual, onChange);
  return (
    <div className="tabs">
      <div role="tablist" aria-label={label} aria-orientation={orientation}>
        {tabs.map(t => (
          <button key={t.id} role="tab" id={`tab-${t.id}`} aria-selected={selected === t.id} aria-controls={`panel-${t.id}`}
            tabIndex={focused === t.id ? 0 : -1}
            onKeyDown={e => onKeyDown(e, t.id)}
            onClick={() => { setSelected(t.id); setFocused(t.id); onChange?.(t.id); }}>{t.label}</button>
        ))}
      </div>
      {tabs.map(t => (
        <div key={t.id} role="tabpanel" id={`panel-${t.id}`} aria-labelledby={`tab-${t.id}`} hidden={selected !== t.id} tabIndex={0}>{t.content}</div>
      ))}
    </div>
  );
}

export function Ago({ iso }: { iso: string }) {
  const diff = Date.now() - new Date(iso).getTime();
  const hrs = Math.floor(diff / 3600000);
  const days = Math.floor(diff / 86400000);
  const text = days > 0 ? `${days} days ago` : `${hrs} hours ago`;
  return <span>{text}</span>;
}

const UNITS: [Intl.RelativeTimeFormatUnit, number][] = [
  ['year', 31536000000], ['month', 2592000000], ['week', 604800000],
  ['day', 86400000], ['hour', 3600000], ['minute', 60000], ['second', 1000],
];
export function relative(iso: string, locale: string): string {
  const diff = new Date(iso).getTime() - Date.now();
  const abs = Math.abs(diff);
  const rtf = new Intl.RelativeTimeFormat(locale, { numeric: 'auto' });
  for (const [unit, ms] of UNITS) {
    if (abs >= ms || unit === 'second') return rtf.format(Math.round(diff / ms), unit);
  }
  return rtf.format(0, 'second');
}
export function refreshMs(iso: string): number {
  const abs = Math.abs(new Date(iso).getTime() - Date.now());
  return abs < 3600000 ? 60000 : 3600000; // refresh minutely under an hour, else hourly
}

import { useEffect, useState } from 'react';
import { relative, refreshMs } from './relativeTime';
export function Ago({ iso, locale }: { iso: string; locale: string }) {
  const [, tick] = useState(0);
  useEffect(() => {
    const id = setInterval(() => tick(x => x + 1), refreshMs(iso));
    return () => clearInterval(id);
  }, [iso]);
  const title = new Intl.DateTimeFormat(locale, { dateStyle: 'long', timeStyle: 'short' }).format(new Date(iso));
  return <time dateTime={iso} aria-label={title} title={title}>{relative(iso, locale)}</time>;
}

