function baseLang(l: string) { return l.split('-')[0]; }
export function resolve(doc: any, locale: string) {
  const t = doc.translations || {};
  const chain = [locale, baseLang(locale), doc.defaultLocale, 'en'];
  for (const l of chain) { const v = t.get ? t.get(l) : t[l]; if (v && v.body && v.status === 'published') return { ...v, resolvedLocale: l }; }
  return null;
}

import { Article, resolve } from './models/article';
export async function getArticle(slug: string, locale: string) {
  const doc = await Article.findOne({ slug });
  if (!doc) return null;
  const r = resolve(doc, locale);
  if (!r) return null;
  // Backward-compatible shape: keep a top-level body for old clients
  return { slug, title: r.title, body: r.body, locale: r.resolvedLocale };
}
export function translationStatus(doc: any) {
  return ['en', 'de', 'fr'].map(l => ({ locale: l, translated: !!(doc.translations.get(l)?.body) }));
}

import { Article } from '../src/models/article';
export async function up() {
  const cursor = Article.find({ body: { $exists: true } }).cursor();
  for await (const doc of cursor as any) {
    if (!doc.translations) doc.translations = new Map();
    doc.translations.set('en', { title: doc.title, body: doc.body, status: 'published' });
