import { useEffect, useRef, useState } from 'react';
export function Wizard({ steps, onValidate }: { steps: { title: string; render: () => React.ReactNode }[]; onValidate?: (i: number) => string | null }) {
  const [i, setI] = useState(0);
  const [announce, setAnnounce] = useState('');
  const headingRef = useRef<HTMLHeadingElement>(null);
  const prev = useRef(0);
  const firstRender = useRef(true);
  useEffect(() => {
    if (firstRender.current) { firstRender.current = false; prev.current = i; return; }
    if (prev.current !== i) {
      headingRef.current?.focus();
      setAnnounce(`Step ${i + 1} of ${steps.length}: ${steps[i].title}`);
      prev.current = i;
      history.replaceState({ step: i }, '');
    }
  }, [i, steps]);
  useEffect(() => {
    const onPop = (e: PopStateEvent) => { if (typeof e.state?.step === 'number') setI(e.state.step); };
    window.addEventListener('popstate', onPop);
    return () => window.removeEventListener('popstate', onPop);
  }, []);
  function next() {
    const err = onValidate?.(i);
    if (err) { document.querySelector<HTMLElement>('[aria-invalid="true"]')?.focus(); return; }
    setI(x => Math.min(x + 1, steps.length - 1));
  }
  return (
    <div className="wizard">
      <h2 ref={headingRef} tabIndex={-1}>{steps[i].title}</h2>
      <div aria-live="polite" className="sr-only">{announce}</div>
      {steps[i].render()}
      <button type="button" onClick={() => setI(x => Math.max(x - 1, 0))} disabled={i === 0}>Back</button>
      <button type="button" onClick={next} disabled={i === steps.length - 1}>Next</button>
    </div>
  );
}

