// GSM 03.38 basic + extension set (subset shown)
const GSM7 = new Set([...'@\u00a3$\u00a5\n\r AaBbCc... 0123456789.,?!:;()/%+-*=#&'.split(''), ...'abcdefghijklmnopqrstuvwxyzABCDEFGHIJKLMNOPQRSTUVWXYZ '.split('')]);
export function isGsm7(s: string): boolean {
  for (const ch of s) if (!GSM7.has(ch)) return false;
  return true;
}
export function segments(s: string): { encoding: 'GSM-7' | 'UCS-2'; count: number } {
  const gsm = isGsm7(s);
  const len = [...s].length;
  if (gsm) return { encoding: 'GSM-7', count: len <= 160 ? 1 : Math.ceil(len / 153) };
  return { encoding: 'UCS-2', count: len <= 70 ? 1 : Math.ceil(len / 67) };
}

import { segments } from './encoding';
const TPL: Record<string, (code: string) => string> = {
  en: c => `${c} is your verification code. Expires in 5 min.`,
  ar: c => `${c} \u0647\u0648 \u0631\u0645\u0632 \u0627\u0644\u062a\u062d\u0642\u0642. \u064a\u0646\u062a\u0647\u064a \u0628\u0639\u062f 5 \u062f\u0642\u0627\u0626\u0642.`,
};
export function otpMessage(locale: string, code: string): string {
  return (TPL[locale] ?? TPL.en)(code);
}
// Build-time guard: ensure no template exceeds 1 segment with a 6-digit code
export function assertSingleSegment(maxSegments = 1) {
  for (const [loc, fn] of Object.entries(TPL)) {
    const { encoding, count } = segments(fn('000000'));
    if (count > maxSegments) throw new Error(`OTP template ${loc} uses ${count} ${encoding} segments (> ${maxSegments})`);
  }
}

import { otpMessage } from './otpTemplates';
import { segments } from './encoding';
export async function sendOtp(phone: string, code: string, locale: string) {
  const text = otpMessage(locale, code);
  const seg = segments(text);
  if (seg.count > 2) throw new Error(`Refusing to send ${seg.count}-segment OTP (cost guardrail)`);
  await provider.send(phone, text, { encoding: seg.encoding });
}

import { FixedSizeList } from 'react-window';
export function Feed({ items }: { items: Post[] }) {
  return (
    <FixedSizeList height={600} itemCount={items.length} itemSize={120} width="100%">
      {({ index, style }) => (
        <div style={style} className="post">{items[index].text}</div>
      )}
    </FixedSizeList>
  );
}

import { useRef, useState } from 'react';
import { FixedSizeList } from 'react-window';
export function Feed({ items, label }: { items: Post[]; label: string }) {
  const listRef = useRef<FixedSizeList>(null);
  const [focused, setFocused] = useState(0);
  function onKeyDown(e: React.KeyboardEvent) {
    let next = focused;
    if (e.key === 'ArrowDown') next = Math.min(focused + 1, items.length - 1);
    else if (e.key === 'ArrowUp') next = Math.max(focused - 1, 0);
    else if (e.key === 'Home') next = 0;
    else if (e.key === 'End') next = items.length - 1;
    if (next !== focused) { e.preventDefault(); setFocused(next); listRef.current?.scrollToItem(next, 'smart'); }
  }
  return (
    <div role="feed" aria-label={`${label} (${items.length})`} onKeyDown={onKeyDown}>
      <FixedSizeList ref={listRef} height={600} itemCount={items.length} itemSize={120} width="100%" overscanCount={3}>
        {({ index, style }) => (
          <article style={style} className="post" role="article"
            aria-setsize={items.length} aria-posinset={index + 1}
            tabIndex={index === focused ? 0 : -1}
            ref={el => { if (index === focused) el?.focus(); }}>
            {items[index].text}
          </article>
        )}
      </FixedSizeList>
    </div>
  );
}

export function RevenueChart({ points }: { points: { date: string; revenue: number }[] }) {
  return (
    <svg width={600} height={300} className="chart">
      {points.map((p, i) => <rect key={i} x={i * 20} y={300 - p.revenue / 100} width={16} height={p.revenue / 100} />)}
      <text x={0} y={295}>Revenue ($)</text>
    </svg>
  );
}

export function tickCurrency(v: number, locale: string, currency: string) {
  return new Intl.NumberFormat(locale, { style: 'currency', currency, notation: 'compact' }).format(v);
}
export function tickDate(iso: string, locale: string) {
  return new Intl.DateTimeFormat(locale, { month: 'short', day: 'numeric' }).format(new Date(iso));
}

import { useT } from './i18n';
import { tickCurrency, tickDate } from './chartFormat';
import { DataTable } from './DataTable';
export function RevenueChart({ points, locale, currency }: { points: { date: string; revenue: number }[]; locale: string; currency: string }) {
  const t = useT();
  const total = points.reduce((s, p) => s + p.revenue, 0);
  const summary = t('chart.revenueSummary', { total: tickCurrency(total / 100, locale, currency), n: points.length });
  return (
    <figure>
      <svg role="img" aria-label={summary} width={600} height={300} className="chart">
        {points.map((p, i) => <rect key={i} x={i * 20} y={300 - p.revenue / 100} width={16} height={p.revenue / 100} />)}
        <text x={0} y={295} aria-hidden="true">{t('chart.revenueAxis')}</text>
      </svg>
      <DataTable
        caption={t('chart.revenueTableCaption')}
        columns={[t('chart.date'), t('chart.revenue')]}
        rows={points.map(p => [tickDate(p.date, locale), tickCurrency(p.revenue / 100, locale, currency)])} />
    </figure>
  );
}

export function DataTable({ caption, columns, rows }: { caption: string; columns: string[]; rows: string[][] }) {
  return (
    <table className="sr-only">
      <caption>{caption}</caption>
      <thead><tr>{columns.map(c => <th key={c} scope="col">{c}</th>)}</tr></thead>
      <tbody>{rows.map((r, i) => <tr key={i}>{r.map((cell, j) => j === 0 ? <th key={j} scope="row">{cell}</th> : <td key={j}>{cell}</td>)}</tr>)}</tbody>
    </table>
  );
}
